colorGreen  = '\033[1;32m'
colorYellow = '\033[1;33m'
colorBlue   = '\033[1;34m'
colorCyan   = '\033[1;36m'

__progname__    = os.path.basename(__file__)
__author__      = 'Luc Suryo'
